import { AzureOpenAI } from 'openai';

const client = new AzureOpenAI({
  azureEndpoint: 'https://your-openai.azure.com/',
  apiKey: 'your-api-key',
  apiVersion: '2024-02-01',
});

async function runResearchQuery(query: string) {
  const thread = await client.beta.threads.create();
  const run = await client.beta.threads.runs.create(thread.id, {
    agent_id: 'research-agent-id',
    instructions: query,
  });
  return run;
}

// Usage
runResearchQuery('Latest quantum computing breakthroughs');

import { RunStep } from 'openai';

function extractToolResults(steps: RunStep[]) {
  return steps
    .filter(step => step.type === 'tool_calls')
    .flatMap(step => 
      step.step_details.tool_calls?.map(tc => ({
        tool: tc.type,
        output: tc.type === 'bing_search' ? tc.bing_results : tc.content
      })) || []
    );
}

