import { VexClient } from 'vex-sdk';

const vex = new VexClient({ apiKey: 'vex-api-key' });

async function validateResearchSources(sources: any[]) {
  const verifications = await Promise.all(
    sources.map(source => 
      Promise.all([
        vex.verifySource(source),
        vex.checkBias(source.content),
        vex.validateClaims(source.content)
      ])
    )
  );

  return verifications.every(results => 
    results[0].valid && results[1].neutral && results[2].accurate
  );
}

